//! Transformer preset for Obfuscator.io / javascript-obfuscator.
//!
//! Includes the full default transformer set plus specialized transforms
//! for patterns generated by Obfuscator.io:
//!
//! - String array decoding (atob, custom base64 alphabets)
//! - Proxy function inlining (included in defaults)
//! - Control flow flattening (future)
//! - Dead code injection removal (included in defaults)

use crate::transformer::Transformer;
use crate::transforms;

/// Returns transformers targeting Obfuscator.io patterns.
pub fn transformers() -> Vec<Box<dyn Transformer>> {
    let mut result = Vec::new();

    // Obfuscator.io-specific transforms run first.
    result.push(
        Box::new(transforms::inlining::StringArrayDecoderTransformer::default())
            as Box<dyn Transformer>,
    );

    // Then all general-purpose transforms.
    result.extend(transforms::default_transformers());

    result
}
